var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"레이라면 지금쯤 이 근처에서 열매를 따고 있을 게다.","JPN":"レイだったら今頃この近くで実を採っているはずだ。","ENG":"Knowing Ray, he should be picking berries somewhere around here about now.","TWN":"雷伊應該正在附近採果實。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이 시기에는 열매가 아주 실하게 익죠. 기억납니다, 숙부님.","JPN":"この時期は実がおいしく熟しますよね。思い出しました、叔父さん。","ENG":"Around this time of year, fruits ripen beautifully. I remember, Uncle.","TWN":"我記得現在是果實正好成熟的時期呢，叔叔。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"하하, 센트럴 팰리스에서는 흙냄새도 맡기 힘들다지?","JPN":"はは、セントラルパレスでは土の匂いも感じないと言っていたな？","ENG":"Haha, I’ve heard it’s difficult to even get a whiff of dirt in Central Palace, eh?","TWN":"哈哈～在聖特羅貝里斯應該很難聞到泥土的味道吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"영주님네 마구간지기와 네가 며칠 뒤에 도망쳐 올지 내기했는데, 벌써 몇 년은 지났구나.","JPN":"お前が何日後に逃げてくるか、領主様の馬屋番と賭けをしたものだが、もう何年も過ぎたとはなあ。","ENG":"I made a bet with our lord's stable keeper on how many days it would be until you came running back, but that was years ago.","TWN":"我那時還和領主家的僕人還打賭，賭你什麼時候會逃回來呢？這都已經過幾年啦？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아내도, 아내의 가문도 저를 인정해 줬습니다. 힘들다고 달아나는 건 무책임한 짓이죠.","JPN":"妻も妻の一門も私を認めてくれました。大変だからといって逃げるのは無責任でしょう。","ENG":"My wife and her family have both acknowledged me. It would have been irresponsible to run away because things were difficult.","TWN":"現在妻子和妻子的家族都已經認同我，況且因為辛苦就逃走，這樣未免太不負責任。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"기왕 출세할 기회를 얻었으니 죽을 각오로 버티라고 당부해 주신 건 숙부님 아니셨습니까?","JPN":"せっかく出世する機会を得たのだから、死ぬ覚悟で耐えろと言ってくださったのは叔父さんでしたよね？","ENG":"Uncle, weren't you the one who told me to persevere with everything I've got because I'd been given a chance to succeed?","TWN":"而且不是叔叔你說，既然有機會可以出人頭地，那死也要撐下去的嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"크흠. 귀족 집안에 데릴사위로 들어가 놓고 마누라랑 그렇게 사이가 좋을지 누가 알았나.","JPN":"こほん。貴族の家柄に婿養子として入っておいて、妻とそんなに仲良くなるとは嬉しい誤算だな。","ENG":"Ahem. Who knew that you would have such a good relationship with your wife after you moved in with your noble in-laws?","TWN":"咳咳，誰知道你入贅貴族之家後，和妻子的感情會那麼好？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"너는 확실히 양이나 치면서 살다 죽기엔 아까운 놈이야.","JPN":"お前は確かに羊飼いなどで一生を終えるには惜しいやつだ。","ENG":"However, there is no doubt that you were meant for more than just shepherding for the rest of your life.","TWN":"你確實是難得一見的人才沒錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"남들과 같은 결혼 생활은 아닙니다. 아내나 저나 서로를 둘도 없는 전우로 여기니 말입니다.","JPN":"一般的な結婚生活ではありません。妻も私もお互いをかけがえのない戦友と思っていますから。","ENG":"My marriage is not like the marriages of others. My wife and I consider each other as irreplaceable comrades.","TWN":"我的婚姻跟一般人不太一樣，我和妻子視彼此為唯一的戰友。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"남녀 사이에 전우는 무슨. 그런 입에 발린 말은 듣기도 싫다.","JPN":"男女間で戦友など。そんな心にもないお世辞は聞きたくもない。","ENG":"Pfft! Comradery between men and women? Now you’re just talking nonsense.","TWN":"男女之間說什麼戰友，這是在曬恩愛嗎？真討厭。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"그보다…… 정말 레이를 데려갈 생각이냐?","JPN":"それより……本当にレイを連れて行くつもりか？","ENG":"Anyway... Are you really thinking of taking Ray with you?","TWN":"不過……你真的打算要帶上雷伊嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"네, 이미 짐도 꾸려 두었습니다.","JPN":"はい、すでに荷物もまとめてあります。","ENG":"Yes, I have already packed his bags.","TWN":"是，行李也都打包好了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"마왕의 추종자들 탓에 오는 길이 지체되었으니, 오늘 바로 함께 수도로 떠날 예정입니다.","JPN":"魔王の取り巻きのせいで来るのが遅れてしまったので、今日にでも一緒に首都に発つ予定です。","ENG":"As we were delayed by the Demon Lord followers on our way over, we will head out for the capital today.","TWN":"都怪魔王的追隨者，害我在來的路上耽擱，所以今天就必須立刻出發去首都。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"솔직히 말하자면 정말 그 아이를 보내도 될지 모르겠다.","JPN":"正直言うと、本当にあの子を送ってもいいのかわからない。","ENG":"To be honest, I’m not sure if sending the boy is a great idea.","TWN":"說老實話，我不知道到底該不該讓他去。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"너와는 달리 수도에서 살기엔 너무 유약한 녀석인데.","JPN":"お前とは違って、首都で暮らすには軟弱すぎるやつだからな。","ENG":"Unlike you, he’s too soft to live in the capital.","TWN":"那孩子和你不同，恐怕沒辦法適應首都的生活。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"너무 걱정하지 마십시오. 레이는 강합니다.","JPN":"あまり心配しないでください。レイは強い子です。","ENG":"Do not worry. Ray is strong.","TWN":"叔叔你別擔心，雷伊很堅強的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"사냥해 온 사슴 모가지도 못 꺾고 쩔쩔 매는 녀석이?","JPN":"狩ってきた鹿の首も折れず、うろたえているやつがか？","ENG":"You mean the kid who even struggles to finish off the deer he brought back from a hunt?","TWN":"你是說獵到鹿後，連扭斷鹿脖子都不敢，在一旁手足無措的小子？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"심성이 착할 뿐이죠.","JPN":"心根が優しいだけでしょう。","ENG":"He is merely kind-hearted.","TWN":"那是因為他心地善良。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"고통스럽게 죽어갈 바에 일찍 죽는 게 낫지. 그건 착한 게 아니라 어리석다고 하는 게야.","JPN":"苦しんで死んでいくよりは早く死ぬ方がいいだろう。そういうのは、優しいんじゃなくて愚かというんだ。","ENG":"It’s better to finish it off quickly than to let it suffer until the end. That’s being foolish, not kind-hearted.","TWN":"那不是善良，而是愚蠢。與其增加牠的痛苦，不如讓牠痛快一點，反正結局都是死。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그렇다면 저는 세상에 둘도 없는 바보겠군요.","JPN":"だったら、私は世に二人といないばかですね。","ENG":"If that’s the case, then I’m the greatest fool in the world.","TWN":"這麼說來，那我應該是最傻的那一個。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전 단 한 번도 그 어리석은 아이를 상대로 대련에서 이겨본 적이 없으니까요.","JPN":"一度もその愚かな子を相手に組手で勝ったことがないんですから。","ENG":"After all, I’ve never defeated that foolish child even once in a sparring match.","TWN":"因為我和那個愚蠢的人練習時，沒有一次打贏他的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"숙부님이 레이를 아들처럼 여기신다는 건 압니다. 하지만 이해해 주십시오.","JPN":"叔父さんがレイを息子のように考えてくださっているのは知っています。でも理解してください。","ENG":"I know you care for Ray as if he’s your son. However, you must understand.","TWN":"我知道叔叔把雷伊當作親生兒子看待，但還請叔叔諒解。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그 아이의 힘은……","JPN":"あの子の力は……","ENG":"His power...","TWN":"因為他的力量……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"다가올 마왕과의 싸움에 꼭 필요할 겁니다.","JPN":"迫る魔王との戦いに必ず必要となるでしょう。","ENG":"We need it for the upcoming battle against the Demon Lord.","TWN":"在即將到來的魔王之戰中，是不可或缺的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"레이! 알렌이 왔다! 이리 와 보거라!","JPN":"レイ！　アレンが来たぞ！　こっちにおいで！","ENG":"Ray! Allen is here! Come say hello!","TWN":"雷伊！艾倫來囉！你快過來！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"아. 오랜만이야, 알렌. 아니, 이젠 버밍엄 경이라고 불러야 할까?","JPN":"あ、久しぶりだね、アレン。いや、これからはバーミンガム卿って呼ばないといけないかな？","ENG":"Oh! Long time no see, Allen. Or should I call you Lord Birmingham now?","TWN":"嗨，艾倫，好久不見，不對，現在應該叫你伯明罕卿嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L33_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아니, 버밍엄 백작가의 정식 후계자는 내 아내인 그레이스다.","JPN":"いや、バーミンガム伯爵家の正式な後継者は妻のグレースだ。","ENG":"No, the official heir to the Earl of Birmingham is my wife, Grace.","TWN":"不，我的妻子 葛瑞絲才是伯明罕伯爵的正統繼承人。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"난 그저 알렌으로 충분해.","JPN":"私はアレンで十分だよ。","ENG":"Just Allen is enough for me.","TWN":"我就是艾倫。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"그렇구나, 그런데 연락도 없이 무슨 일이야? 기사단 때문에 바쁘다고 하지 않았어?","JPN":"なるほどね。ところで連絡なしでいきなりどうしたの？　騎士団で忙しいって言ってなかった？","ENG":"I see. But what brings you here all the sudden? Didn’t you say that you were busy because of the Order?","TWN":"原來如此，不過你怎麼會沒說一聲就跑來，有什麼事嗎？你不是說騎士團很忙嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"알렌이 네게 들어야 할 대답이 있다고 하더구나.","JPN":"アレンがお前から聞かなくてはならない答えがあるそうだ。","ENG":"Allen says that he has something to ask you.","TWN":"艾倫說他還在等你的答案。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"마을에서 기다리기엔 바쁘다고 해서 여기까지 데려왔지.","JPN":"村で待つには忙しいというから、ここまで連れてきた。","ENG":"However, as he is too busy to wait in the village, I have brought him here.","TWN":"他說他趕時間，沒辦法在村里等，所以我就直接把他帶來囉。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"들어야 할 대답……?","JPN":"聞かなくてはならない答え……？","ENG":"Something to ask...?","TWN":"等我的答案……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"혹시, 같이 수도로 가자던 그거 말이야?","JPN":"もしかして、一緒に首都に行こうって言ったこと？","ENG":"Is it about whether I wanted to go to the capital with you?","TWN":"是在說一起去首都那件事嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그래. 그 얘기다.","JPN":"そう。その話だ。","ENG":"Yes, that is correct.","TWN":"沒錯，就是那件事。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"숙부님, 잠시 레이와 단둘이 얘기해도 되겠습니까?","JPN":"叔父さん、しばらくレイと二人っきりで話をさせてもらえませんか？","ENG":"Uncle, would it be okay if Ray and I talked in private?","TWN":"叔叔，我可以單獨和雷伊說幾句話嗎？ "},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"그래, 알겠다. 자리를 비켜 주마.","JPN":"うむ、わかった。席を外そう。","ENG":"Sure. I’ll give you two some space.","TWN":"當然，那我就不打擾你們囉。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"하지만 너무 몰아세우지는 마라.","JPN":"だが、あまり責め立てるなよ。","ENG":"However, don’t push him too much to accept your offer.","TWN":"不過可別把人逼太緊，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"등 떠밀려 결정하는 건 밀린 쪽에게나 민 쪽에게나 달갑지 않은 일이야.","JPN":"背中を押されて決めるのは、押した方も押された方も満足できないものだ。","ENG":"If a decision is made against one’s will, neither party will be happy with the result.","TWN":"畢竟被逼著做決定時，無論是被逼的一方，或是逼人的一方，心裡都不好過的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNCLE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"생각할 시간은 충분했을 거다. 이제는 결정을 내릴 때야.","JPN":"考える時間は十分だったはずだ。もう決める時だよ。","ENG":"You’ve had plenty of time to consider. It’s now time to make a decision.","TWN":"你充分考慮過了吧，是時候做出決定了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"레이, 나와 같이 수도로 가자. 아르카데나 제국에는 네 힘이 필요해.","JPN":"レイ、私と一緒に首都に行こう。アルカデナ帝国には君の力が必要だ。","ENG":"Ray, come with me to the capital. The Empire of Arcadena needs your power.","TWN":"雷伊，和我一起去首都吧，艾爾卡特納帝國需要你。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"그 얘기라면 저번에도 대답했잖아. 난 도시랑 잘 맞는 체질이 아니야, 알렌.","JPN":"その話だったらこの間も答えたじゃないか。僕は都市に向いてないよ、アレン。","ENG":"I already gave you my answer last time. I’m not fit to live in the city, Allen.","TWN":"艾倫，如果你是要談這件事，那我上次也已經回答過你，我不適合在都市生活。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"밭일을 돕고, 숲에서 열매를 챙기고 가끔은 말을 돌보고…….","JPN":"畑仕事を手伝って、森で実を採って、時々馬の世話をして……","ENG":"Helping out in the fields, gathering fruit from the forest, and looking after the horses once in a while...","TWN":"像現在這樣種種田，去森林採採果實，偶爾照顧馬的生活……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"나는 이런 생활이 싫지 않아. 아니, 오히려 좋아해.","JPN":"僕はこの生活が嫌いじゃない。いや、むしろ好きなんだ。","ENG":"I don’t dislike this kind of life. In fact, I enjoy it.","TWN":"老實說我並不討厭，不對，反而還蠻喜歡的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"네가 싸움을 싫어한다는 건 나도 잘 알아, 레이.","JPN":"君が争いを嫌うことは私もよく知っているよ、レイ。","ENG":"I know well enough that you don’t like to fight, Ray.","TWN":"雷伊，我也知道你不喜歡打打殺殺的，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 우리에겐 남은 시간이 얼마 없다.","JPN":"だけど、私たちには残された時間があまりないんだ。","ENG":"However, we don’t have a lot of time.","TWN":"但我們已經沒什麼時間了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"마왕의 군세는 지금도 거침없이 가까워지고 있어.","JPN":"魔王の軍勢は今も止まることなく近づいてきている。","ENG":"The Demon Lord’s armies are inching closer as we speak.","TWN":"魔王的勢力一直在逼近當中，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이런 변방의 마을이라도 그 정도 소문은 들었을 테지.","JPN":"こんな辺境の村でもその程度の噂は聞いたことがあるだろう。","ENG":"You must’ve heard such rumors even in a village on the outskirts like this.","TWN":"相信這件事即使在這個偏僻的村莊裡，也是略有所聞。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이 마을도, 네가 누리던 자유로운 시간들도, 언제 놈들에게 잿더미가 될지 모른다.","JPN":"この村も、君が謳歌していた自由な時間も、いつあいつらに灰にされるかわからない。","ENG":"This village, the freedom you enjoy... You never know when they will reduce them to ashes.","TWN":"無論是這座村莊，或是你曾經有過的那些自由，都不知何時會被那些傢伙給毀掉。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그 때가 되면 막을 수 없어. 돌이키기에는 이미 늦었을 테니까.","JPN":"その時になったら止められない。取り戻すにはもう遅すぎるだろうからね。","ENG":"When that time comes, we will be hopeless to stop them. It’ll be too late by then.","TWN":"到那時候就真的來不及了，因為已經覆水難收。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"알렌, 나는…….","JPN":"アレン、僕は……","ENG":"Allen, I...","TWN":"艾倫，我……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"숙부님은 아직도 당신을 덮친 곰을 내가 벤 줄 알고 계시더군.","JPN":"叔父さんはまだ自身を襲った熊を私が斬ったと思っているようだった。","ENG":"Uncle still thinks that I’m the one who defeated the bear that attacked him.","TWN":"叔叔到現在都還以為，是我把那隻撲向他的熊殺死的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That’s...","TWN":"那是……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"레이. 코흘리개였던 네가 이빨 나간 칼로 그 일을 해냈을 때부터, 나는 줄곧 믿고 있었다.","JPN":"レイ。幼かった君が刃こぼれした剣でそれをやり遂げた時から、私はずっと信じていた。","ENG":"Ray. I've always believed in you since I saw you, a snot-nosed kid, perform that deed with a dull blade.","TWN":"雷伊，當我看到年幼的你拿起刀殺死熊時，我就相信，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"네 힘은 누군가를 구하는 데 쓰여야 해. 그게 바로 네게 그런 힘이 주어진 이유야.","JPN":"君の力は誰かを助けるために使わなければ。それが君に力が与えられた理由だ。","ENG":"Your power must be used to save others. That is why you were granted such power.","TWN":"你的力量必須用來救人，這也是你之所以有那股力量的原因。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"알렌…….","JPN":"アレン……","ENG":"Allen...","TWN":"艾倫……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"곧 출정이다. 전황을 보면, 다음에 다시 만날 수 있을 거라고 장담하긴 어려워.","JPN":"もうすぐ出陣だ。戦況から見れば、次にまた会えるとは断言できない。","ENG":"I must go off to war soon. Judging by the reports from the front, I can’t guarantee that we’ll be able to see each other again.","TWN":"就要出征了，照戰況看來，我無法保證我們還能夠再見面。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 네가 우리와 함께해 준다면……. 모두가 무사히 돌아올 수 있을 거다.","JPN":"しかし、君が一緒に戦ってくれるなら……みんなが無事に戻ることができるはずだ。","ENG":"However, if you stand by my side... We may all be able to return home safely.","TWN":"但只要你願意加入我們……我們就可以平安歸來。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"내가 알렌을……. 사람들을 구할 수 있을 거라고?","JPN":"僕がアレンを……人々を救える？","ENG":"You’re saying that I can save you... and the others too?","TWN":"我可以救你……救大家？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그래. 설령 이 세상에 구원이란 게 없더라도…….","JPN":"そうだ。たとえ世界に救いというものが無かったとしても……","ENG":"Yes. Even if there is no such thing as salvation for this world...","TWN":"沒錯，就算世界上沒有所謂的救贖……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"누군가는 그들을 도울 수 있을지도 모르지.","JPN":"誰かは人々を救うことができるかもしれない。","ENG":"Someone may be able to help the people.","TWN":"或許也有那麼一個人可以幫助大家。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"나는……. 그 누군가가 너라고 믿는다.","JPN":"私は……その誰かが君だと信じている。","ENG":"And I... believe that someone is you.","TWN":"而我相信……那個人就是你。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};